// --- Validation (Backend Steering → Workflow 1, Node 1) ---
const body = $input.first().json.body || $input.first().json;

const userId = body.user_id;
const itemName = (body.item_name || '').toString().trim();
const price = parseFloat(body.price);
const rawCategory = body.raw_category ? body.raw_category.toString().trim() : null;
const clientTimestamp = body.client_timestamp;
const timezone = body.timezone;

const errors = [];
if (!userId) errors.push('user_id zorunludur');
if (!itemName) errors.push('item_name boş olamaz');
if (isNaN(price) || price <= 0) errors.push('price 0\'dan büyük olmalı');

if (errors.length > 0) {
  // 400 Bad Request — frontend'e erken döner
  throw new Error('VALIDATION_FAILED: ' + errors.join('; '));
}

return [{
  json: {
    user_id: userId,
    item_name: itemName,
    price: price,
    raw_category: rawCategory,
    client_timestamp: clientTimestamp,
    timezone: timezone
  }
}];

// LLM yanıtını temizle + known sete zorla; değilse 'Diğer' (fallback).
const KNOWN = ['Yemek','İçecek','Giyim','Eğlence','Ulaşım','Teknoloji','Kişisel Bakım','Diğer'];
const raw = ($input.first().json.content || '').toString().trim();
const match = KNOWN.find(k => raw.toLowerCase().includes(k.toLowerCase()));
return [{ json: { ai_category: match || 'Diğer' } }];

// --- Fallback (Steering → Hata Yönetimi) ---
// LLM başarısız olursa ai_category = 'Diğer' ile devam et, sistemi çökertme.
return [{
  json: {
    ...$input.first().json,
    ai_category: 'Diğer'
  }
}];
